const soldVariantIds = new Set();

const ordersData = $input.first().json;
const orders = ordersData.entries || [];

for (const order of orders) {
  if (order.typeId !== 1) continue;
  if (order.orderItems) {
    for (const item of order.orderItems) {
      if (item.typeId === 1 && item.itemVariationId) {
        soldVariantIds.add(item.itemVariationId);
      }
    }
  }
}

// Output each sold ID as a separate object
const result = [];
for (const id of soldVariantIds) {
  result.push({ soldVariantId: id });
}
return result;

function round2(n) { return Math.round(n * 100) / 100; }

function parseDate(val) {
  if (!val || val === '' || val === 'null') return null;
  const d = new Date(val);
  return isNaN(d.getTime()) ? null : d;
}

function daysBetween(from, to) {
  if (!from) return 999;
  return Math.floor((to - from) / (1000 * 60 * 60 * 24));
}

const today = new Date();
const result = [];

for (const item of $input.all()) {
  const j = item.json;

  // floorPrice: string from Calc nodes, parseFloat handles it
  const floorPrice = round2(
    j.tagId === '16'
      ? parseFloat(j.floorPrice16 || 0)
      : parseFloat(j.floorPrice17 || 0)
  );

  // price3: nested object from Edit Fields / Set fields
  const price3 = round2(parseFloat(
    (j.variationSalesPrices3 && j.variationSalesPrices3.price3)
    || 0
  ));

  // currentPrice17: nested object, 0 = not set (treat as null)
  const rawPrice17 = parseFloat(
    (j.variationSalesPrices17 && j.variationSalesPrices17.price17)
    || 0
  );
  const currentPrice17 = rawPrice17 === 0 ? null : round2(rawPrice17);

  // State fields from Google Sheets (column names with spaces)
  const currentStage = j['Current Stage'] || j.currentStage || 'UNINITIALIZED';
  const daysAtFloorCounter = parseInt(j['Days at Floor'] || j.daysAtFloorCounter || 0, 10);

  const lastPriceChangeDate = parseDate(j['Last Price Change'] || j.lastPriceChangeDate || null);
  const lastSaleDate = parseDate(j['Last Sale Date'] || j.lastSaleDate || null);

  // 999 = sentinel for "never happened" → ensures stage1_init triggers on first run
  const daysSinceLastChange = daysBetween(lastPriceChangeDate, today);
  const daysSinceLastSale = daysBetween(lastSaleDate, today);

  // soldToday: soldVariantId present and matches this variant's Variant ID
  const varId = Number(j.variantId || j['Variant ID']);
  const soldToday = (j.soldVariantId !== undefined && j.soldVariantId !== null)
    && (Number(j.soldVariantId) === varId);

  result.push({
    json: {
      variantId: varId,
      itemId: Number(j.itemId || j['Item ID']),
      number: j.number || j['Variant Nr'],
      tagId: String(j.tagId || j['Tag ID']),
      netStock: Number(j.netStock),
      EK: round2(parseFloat(j.EK || 0)),
      price3,
      currentPrice17,
      floorPrice,
      currentStage,
      daysAtFloorCounter,
      lastPriceChangeDate: lastPriceChangeDate ? lastPriceChangeDate.toISOString() : null,
      lastSaleDate: lastSaleDate ? lastSaleDate.toISOString() : null,
      daysSinceLastChange,
      daysSinceLastSale,
      soldToday
    }
  });
}

return result;
